module dff
  (input  clk,
   input  d,
   input  load,
   output q);
  wire r;
  wire rin;
  wire n4_o;
  reg n5_o;
  reg n11_q;
  assign q = r;
  assign r = n11_q;
  assign rin = n5_o;
  assign n4_o = load == 1'b1;
  always @*
    case (n4_o)
      1'b1: n5_o <= d;
    endcase
  always @(posedge clk)
    n11_q <= rin;
endmodule
